const s=["周日","周一","周二","周三","周四","周五","周六"];function c(t){if(!t)return"";const e=new Date(t),n=String(e.getHours()).padStart(2,"0"),a=String(e.getMinutes()).padStart(2,"0");return`${n}:${a}`}function i(t=new Date){const e=t.getMonth()+1,n=t.getDate(),a=s[t.getDay()];return`今日 · ${e}月${n}日 ${a}`}function r(t=new Date){const e=n=>String(n).padStart(2,"0");return`${t.getFullYear()}-${e(t.getMonth()+1)}-${e(t.getDate())}`}function u(t){return t?String(t).slice(0,10):""}function g(t,e=new Date){const n=r(e);return[...t].filter(a=>u(a.startTime)===n).sort((a,o)=>new Date(a.startTime)-new Date(o.startTime))}function D(t=new Date){const e=r(t);return{from:`${e}T00:00:00`,to:`${e}T23:59:59`}}function f(){return new Date().toISOString()}export{i as a,g as b,c as f,D as g,f as n};
